import React, { useState, useEffect } from 'react';
import {
    Box,
    IconButton,
    Typography,
    CircularProgress,
    Dialog,
    DialogTitle,
    DialogContent,
    Snackbar,
    Alert
} from '@mui/material';
import {
    NavigateBefore,
    NavigateNext,
    Fullscreen,
    FullscreenExit,
    Download
} from '@mui/icons-material';
import { motion, AnimatePresence } from 'framer-motion';

const PhotoBookPreview = ({ photoBookId, currentPage, totalPages, onPageChange }) => {
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [fullscreen, setFullscreen] = useState(false);
    const [pageImage, setPageImage] = useState(null);
    const [downloading, setDownloading] = useState(false);

    useEffect(() => {
        loadPagePreview();
    }, [photoBookId, currentPage]);

    const loadPagePreview = async () => {
        try {
            setLoading(true);
            setError(null);
            const response = await fetch(`/api/photobooks/${photoBookId}/pages/${currentPage}/preview`);
            if (!response.ok) {
                throw new Error('Failed to load page preview');
            }
            const imageBlob = await response.blob();
            setPageImage(URL.createObjectURL(imageBlob));
        } catch (err) {
            setError('Ошибка загрузки предпросмотра страницы');
            console.error('Error loading preview:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleDownload = async () => {
        try {
            setDownloading(true);
            const response = await fetch(`/api/photobooks/${photoBookId}/download`);
            if (!response.ok) {
                throw new Error('Failed to download photobook');
            }
            const blob = await response.blob();
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `photobook-${photoBookId}.pdf`;
            document.body.appendChild(a);
            a.click();
            window.URL.revokeObjectURL(url);
            document.body.removeChild(a);
        } catch (err) {
            setError('Ошибка при скачивании фотокниги');
            console.error('Error downloading photobook:', err);
        } finally {
            setDownloading(false);
        }
    };

    const handlePreviousPage = () => {
        if (currentPage > 1) {
            onPageChange(currentPage - 1);
        }
    };

    const handleNextPage = () => {
        if (currentPage < totalPages) {
            onPageChange(currentPage + 1);
        }
    };

    const renderPreview = () => (
        <Box
            sx={{
                position: 'relative',
                width: '100%',
                height: '100%',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                bgcolor: 'background.paper',
                borderRadius: 1,
                overflow: 'hidden'
            }}
        >
            {/* Верхняя панель */}
            <Box
                sx={{
                    width: '100%',
                    p: 1,
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    borderBottom: 1,
                    borderColor: 'divider'
                }}
            >
                <Typography variant="subtitle1">
                    Страница {currentPage} из {totalPages}
                </Typography>
                <Box>
                    <IconButton
                        onClick={handleDownload}
                        disabled={downloading}
                        title="Скачать фотокнигу"
                    >
                        {downloading ? <CircularProgress size={24} /> : <Download />}
                    </IconButton>
                    <IconButton
                        onClick={() => setFullscreen(!fullscreen)}
                        title={fullscreen ? 'Выйти из полноэкранного режима' : 'Полноэкранный режим'}
                    >
                        {fullscreen ? <FullscreenExit /> : <Fullscreen />}
                    </IconButton>
                </Box>
            </Box>

            {/* Область предпросмотра */}
            <Box
                sx={{
                    position: 'relative',
                    flex: 1,
                    width: '100%',
                    display: 'flex',
                    justifyContent: 'center',
                    alignItems: 'center',
                    p: 2
                }}
            >
                {loading ? (
                    <CircularProgress />
                ) : error ? (
                    <Typography color="error" align="center">
                        {error}
                        <br />
                        <Button onClick={loadPagePreview} sx={{ mt: 1 }}>
                            Повторить загрузку
                        </Button>
                    </Typography>
                ) : (
                    <AnimatePresence mode="wait">
                        <motion.img
                            key={currentPage}
                            src={pageImage}
                            alt={`Page ${currentPage}`}
                            style={{
                                maxWidth: '100%',
                                maxHeight: '100%',
                                objectFit: 'contain',
                                boxShadow: '0 4px 8px rgba(0,0,0,0.1)'
                            }}
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.8 }}
                            transition={{ duration: 0.3 }}
                        />
                    </AnimatePresence>
                )}

                {/* Кнопки навигации */}
                <IconButton
                    sx={{
                        position: 'absolute',
                        left: 8,
                        top: '50%',
                        transform: 'translateY(-50%)',
                        bgcolor: 'background.paper',
                        '&:hover': { bgcolor: 'action.hover' }
                    }}
                    onClick={handlePreviousPage}
                    disabled={currentPage <= 1 || loading}
                >
                    <NavigateBefore />
                </IconButton>

                <IconButton
                    sx={{
                        position: 'absolute',
                        right: 8,
                        top: '50%',
                        transform: 'translateY(-50%)',
                        bgcolor: 'background.paper',
                        '&:hover': { bgcolor: 'action.hover' }
                    }}
                    onClick={handleNextPage}
                    disabled={currentPage >= totalPages || loading}
                >
                    <NavigateNext />
                </IconButton>
            </Box>
        </Box>
    );

    return (
        <>
            {fullscreen ? (
                <Dialog
                    fullScreen
                    open={true}
                    onClose={() => setFullscreen(false)}
                >
                    <DialogTitle>
                        Предпросмотр фотокниги
                    </DialogTitle>
                    <DialogContent>
                        {renderPreview()}
                    </DialogContent>
                </Dialog>
            ) : (
                renderPreview()
            )}

            <Snackbar
                open={!!error}
                autoHideDuration={6000}
                onClose={() => setError(null)}
            >
                <Alert severity="error" onClose={() => setError(null)}>
                    {error}
                </Alert>
            </Snackbar>
        </>
    );
};

export default PhotoBookPreview;
